"use client";

/* ════════════════════════════════════════════════════════════════════════
   Study · Build — the split canvas (study spec §4.2).
   Left: navy conversation companion (foldable + resizable). Right: parchment
   workbench whose artifact (a brand-voiced email) renders white, a "Magellan's
   plan" band, and the navy Push-to-Bridge commit. Ported from
   magellan-study-3-build.html. onClose returns to the conversation thread.
   ════════════════════════════════════════════════════════════════════════ */

import { useState } from "react";
import { useRouter } from "next/navigation";
import "./StudyBuild.css";

const RAIL_W = 96;

export function StudyBuild({ onClose }: { onClose: () => void }) {
  const router = useRouter();
  const [folded, setFolded] = useState(false);
  const [convoW, setConvoW] = useState(424);
  const [dragging, setDragging] = useState(false);
  const [view, setView] = useState<"preview" | "code">("preview");
  const [device, setDevice] = useState<"desktop" | "mobile">("desktop");
  const [pushed, setPushed] = useState(false);
  const [draft, setDraft] = useState("");
  const [extra, setExtra] = useState<Array<{ role: "you" | "mag"; text: string }>>([]);

  const clamp = (v: number) => {
    const max = Math.min(typeof window !== "undefined" ? window.innerWidth * 0.6 : 720, 720);
    return Math.max(320, Math.min(max, v));
  };

  const sendRefine = () => {
    const text = draft.trim();
    if (!text) return;
    setExtra((m) => [...m, { role: "you", text }]);
    setDraft("");
    setTimeout(() => setExtra((m) => [...m, { role: "mag", text: "Updated — take a look on the right." }]), 800);
  };

  return (
    <div
      className={`study-build${folded ? " folded" : ""}${device === "mobile" ? " mail-mobile" : ""}`}
      style={{ ["--convo-w" as string]: `${convoW}px` } as React.CSSProperties}
    >
      {/* ── LEFT — conversation companion ── */}
      <aside className="convo">
        <div className="convo-head">
          <div className="ch-avatar">M</div>
          <div className="ch-id">
            <div className="ch-name">Magellan</div>
            <div className="ch-scope"><span className="dot" />Building · Mother&rsquo;s Day email</div>
          </div>
          <button className="ch-fold" title="Focus on the work" type="button" onClick={() => setFolded(true)}>
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><polyline points="15 18 9 12 15 6" /></svg>
          </button>
        </div>

        <div className="convo-body">
          <div className="day">Today · 10:22 AM</div>
          <div className="msg-you">Make the Mother&rsquo;s Day one warmer. Less about premium positioning, more about the relationship.<span className="t">10:22</span></div>
          <div className="msg-mag">
            <div className="who">Magellan · 10:23</div>
            <div className="body">
              Updated. The opener now leads with the customers who&rsquo;ve ordered three Mother&rsquo;s Days running — <span className="good">23%</span> of last year&rsquo;s buyers are repeat. Premium framing is still there, underneath rather than on top.
              <button className="art-ref" type="button">
                <span className="art-ref-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M4 4h16v16H4z" /><path d="M4 8h16" /></svg></span>
                <span className="art-ref-tx"><span className="art-ref-k" style={{ display: "block" }}>Email · Editing</span><span className="art-ref-t" style={{ display: "block" }}>Mother&rsquo;s Day · May 11</span></span>
                <span className="art-ref-arrow">→</span>
              </button>
            </div>
          </div>
          <div className="msg-you">Good. The opener works. Swap the hero image to something warmer — current lavender feels editorial.<span className="t">10:25</span></div>
          <div className="msg-mag">
            <div className="who">Magellan · 10:25</div>
            <div className="body">Switched to a softer dawn palette — warm pinks and apricots pulled from your wedding catalog. The selected one reads as familiar rather than aspirational.</div>
          </div>
          <div className="msg-mag">
            <div className="who">Magellan · 10:27</div>
            <div className="body">I think it&rsquo;s ready. Set to reach <span className="good">2,847</span> repeat Mother&rsquo;s Day customers, Sun May 11 at 8:00 AM, anchored at <span className="good">$2,100</span> to hold the premium read.<br /><br /><span className="soft">Push to Bridge whenever you want and I&rsquo;ll line it up for your final approval. Nothing ships until you say so.</span></div>
          </div>
          {extra.map((m, i) =>
            m.role === "you" ? (
              <div key={i} className="msg-you">{m.text}</div>
            ) : (
              <div key={i} className="msg-mag"><div className="who">Magellan</div><div className="body">{m.text}</div></div>
            )
          )}
        </div>

        <div className="convo-composer">
          <div className="cc-foot"><span className="dot" />Scoped to Mother&rsquo;s Day email</div>
          <div className="cc-wrap">
            <input
              className="cc-input"
              placeholder="Refine it — Magellan is listening…"
              value={draft}
              onChange={(e) => setDraft(e.target.value)}
              onKeyDown={(e) => { if (e.key === "Enter") { e.preventDefault(); sendRefine(); } }}
            />
            <div className="cc-row">
              <button className="cc-btn" title="Attach" type="button">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48" /></svg>
              </button>
              <span className="cc-spacer" />
              <button className="cc-mic" title="Hold to talk" type="button">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M12 1a3 3 0 00-3 3v8a3 3 0 006 0V4a3 3 0 00-3-3z" /><path d="M19 10v2a7 7 0 01-14 0v-2" /><line x1="12" y1="19" x2="12" y2="23" /><line x1="8" y1="23" x2="16" y2="23" /></svg>
              </button>
              <button className="cc-send" title="Send" type="button" onClick={sendRefine}>
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><line x1="12" y1="19" x2="12" y2="5" /><polyline points="5 12 12 5 19 12" /></svg>
              </button>
            </div>
          </div>
        </div>
      </aside>

      {/* resizer */}
      <div
        className={`resizer${dragging ? " dragging" : ""}`}
        title="Drag to resize · double-click to reset"
        onPointerDown={(e) => { setDragging(true); e.currentTarget.setPointerCapture(e.pointerId); }}
        onPointerMove={(e) => { if (dragging) setConvoW(clamp(e.clientX - RAIL_W)); }}
        onPointerUp={(e) => { setDragging(false); e.currentTarget.releasePointerCapture(e.pointerId); }}
        onDoubleClick={() => setConvoW(424)}
      >
        <div className="resizer-grip" />
      </div>

      {/* sliver to bring the companion back */}
      <button className="unfold" title="Show Magellan" type="button" onClick={() => setFolded(false)}>
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><polyline points="9 18 15 12 9 6" /></svg>
      </button>

      {/* ── RIGHT — workbench ── */}
      <main className="work">
        <div className="work-head">
          <div className="wh-meta">
            <div className="wh-kicker">Email · <span className="edit">Editing</span> · auto-saved 10:27</div>
            <div className="wh-title">Three Mother&rsquo;s Days in a row — and counting</div>
          </div>
          <div className="wh-controls">
            <div className="seg">
              <button className={view === "preview" ? "active" : ""} type="button" onClick={() => setView("preview")}>Preview</button>
              <button className={view === "code" ? "active" : ""} type="button" onClick={() => setView("code")}>Code</button>
            </div>
            <div className="seg">
              <button className={device === "desktop" ? "active" : ""} type="button" onClick={() => setDevice("desktop")}>Desktop</button>
              <button className={device === "mobile" ? "active" : ""} type="button" onClick={() => setDevice("mobile")}>Mobile</button>
            </div>
            <button className="wh-icon" title="Download" type="button">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4" /><polyline points="7 10 12 15 17 10" /><line x1="12" y1="15" x2="12" y2="3" /></svg>
            </button>
            <button className="wh-icon" title="Close" type="button" onClick={onClose}>
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" /></svg>
            </button>
          </div>
        </div>

        <div className="work-body">
          <div className="email">
            <div className="email-col">
              <div className="mail-meta">
                <div className="mail-subject">Three Mother&rsquo;s Days in a row — and counting</div>
                <div className="mail-labels"><span className="mail-label">Inbox</span><span className="mail-label">Mother&rsquo;s Day</span></div>
              </div>
              <div className="mail-from">
                <div className="mail-from-avatar">U</div>
                <div>
                  <div className="mail-from-name">UrbanFlowers Bangkok <span className="to">to you</span></div>
                  <div className="mail-from-detail">hello@urbanflowers.co.th · May 11, 8:00 AM</div>
                </div>
              </div>
              <div className="mail-hero">
                <div className="mail-hero-kicker">For Mother&rsquo;s Day · May 11</div>
                <div className="mail-hero-title">Hello, again.</div>
                <div className="mail-hero-rule" />
              </div>
              <div className="mail-para">Three years ago, 184 of you ordered flowers for your mother for the first time. Last year, you came back. The year before that too.</div>
              <div className="mail-para">We notice these things. Not because we track customers — we don&rsquo;t really think of you that way — but because three Mother&rsquo;s Days in a row is its own kind of relationship. With her. With us. With the idea that some things deserve to become tradition.</div>
              <div className="mail-para">This year we&rsquo;ve put together three arrangements for the people who&rsquo;ve shown up again and again. Each references something we&rsquo;ve learned about what your mothers love — softer palettes, longer-lasting blooms, the small detail that makes it feel like <i>your</i> bouquet, not a bouquet.</div>
              <div className="mail-cta-row"><span className="mail-cta">See the three arrangements →</span></div>
              <div className="mail-signoff">Thank you for letting us be part of your tradition.<br />— Johannes &amp; the UrbanFlowers team</div>
              <div className="mail-footer">
                <div className="mail-footer-brand">UrbanFlowers Bangkok</div>
                <div>89/12 Charoenkrung Soi 30, Bangrak, Bangkok 10500</div>
                <div style={{ marginTop: 6 }}><a href="#">Unsubscribe</a> · <a href="#">Update preferences</a> · <a href="#">View in browser</a></div>
              </div>
            </div>
          </div>

          <div className="plan">
            <div className="plan-col">
              <div className="plan-kicker">Magellan&rsquo;s plan</div>
              <div className="plan-note">Review before pushing to Bridge. Each setting can be changed.</div>
              <div className="plan-card">
                <div className="es-row">
                  <div className="es-label">Recipients</div>
                  <div className="es-value"><span className="es-pill active">Repeat MD customers</span><span className="es-pill">All subscribers</span><span className="es-pill">VIP only</span><span className="es-stat"><b>2,847</b> people</span></div>
                </div>
                <div className="es-row">
                  <div className="es-label">Send time</div>
                  <div className="es-value"><span className="es-pill active">May 11 · 8:00 AM</span><span className="es-pill">Custom…</span><span className="es-stat"><b>Local</b></span></div>
                </div>
                <div className="es-row">
                  <div className="es-label">AOV anchor</div>
                  <div className="es-value"><span className="es-pill active">$2,100</span><span className="es-stat"><b>Premium</b> anchored</span></div>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="work-foot">
          <div className="wf-status">
            <span className="dot" />
            {pushed ? "Staged · awaiting your approval in Record" : "Draft ready · nothing ships until you approve"}
          </div>
          <div className="wf-spacer" />
          <button className="btn-save" type="button">Save to memory</button>
          <button
            className={`btn-push${pushed ? " pushed" : ""}`}
            type="button"
            onClick={() => {
              // Push stages the artifact in Record · Waiting (study spec §4.4 / §5):
              // show the confirm, then route to the ledger so the hand-off is visible.
              setPushed(true);
              setTimeout(() => router.push("/study/record"), 900);
            }}
          >
            <span>{pushed ? "Pushed to Bridge ✓" : "Push to Bridge"}</span>
            {!pushed && (
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><line x1="5" y1="12" x2="19" y2="12" /><polyline points="12 5 19 12 12 19" /></svg>
            )}
          </button>
        </div>
      </main>
    </div>
  );
}
